using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    int K = static_cast<int>(k);

    if (K > 10) {
        K = 10;
    }

    vector<vector<vector<long long>>> dp(m, vector<vector<long long>>(n, vector<long long>(K + 1, LLONG_MAX)));
    auto cmp = [](const tuple<long long, int, int, int>& a, const tuple<long long, int, int, int>& b) {
        return get<0>(a) > get<0>(b);
    };
    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, decltype(cmp)> pq(cmp);

    vector<pair<int, int>> dirs = {{0, 1}, {1, 0}};

    dp[0][0][0] = 0;
    pq.push(make_tuple(0, 0, 0, 0));

    while (!pq.empty()) {
        auto [cost, i, j, t] = pq.top();
        pq.pop();

        if (cost != dp[i][j][t]) {
            continue;
        }

        for (auto& d : dirs) {
            int ni = i + d.first;
            int nj = j + d.second;
            if (ni < 0 || ni >= m || nj < 0 || nj >= n) 
                continue;
            long long ncost = cost + grid[ni][nj];
            if (ncost < dp[ni][nj][t]) {
                dp[ni][nj][t] = ncost;
                pq.push(make_tuple(ncost, ni, nj, t));
            }
        }

        if (t < K) {
            for (int x = 0; x < m; x++) {
                for (int y = 0; y < n; y++) {
                    if (x == i && y == j) 
                        continue;
                    if (grid[x][y] <= grid[i][j]) {
                        long long ncost = cost;
                        int nt = t + 1;
                        if (ncost < dp[x][y][nt]) {
                            dp[x][y][nt] = ncost;
                            pq.push(make_tuple(ncost, x, y, nt));
                        }
                    }
                }
            }
        }
    }

    long long ans = LLONG_MAX;
    for (int t = 0; t <= K; t++) {
        if (dp[m - 1][n - 1][t] < ans) {
            ans = dp[m - 1][n - 1][t];
        }
    }
    return ans;
}
