import std.algorithm: min;
import std.container: heap, Array;
import std.stdio: writefln;

// Helper: MinHeap based on the first element (cost) of the tuple.
alias State = Tuple!(Int64, Int, Int, Int);

// Custom comparator for min-heap based on the first element of the tuple.
bool stateLess(State a, State b) {
    return a[0] < b[0];
}

alias MinHeap = Array!State;

State front(MinHeap heap) {
    return heap[0];
}

void removeFront(ref MinHeap heap) {
    heap.removeFront();
}

void insert(ref MinHeap heap, State value) {
    heap ~= value;
    heap.heapify!stateLess;  // Reheapify to maintain min-heap property
}

void heapify(ref MinHeap heap) {
    heap.heapify!stateLess;
}

func solve(grid: Array<Array<Int64>>, k: Int64) -> Int64 {
    Int m = grid.size();
    if (m == 0) return -1;
    Int n = grid[0].size();
    Int k_val = k.toInt();

    Int64 INF = 1_000_000_000_000_000;

    // 3D DP array: [m][n][k_val+1]
    Array<Array<Array<Int64>>> dp = Array!Array!Array!Int64(m);
    for (Int i=0; i < m; i++) {
        dp[i] = Array!Array!Int64(n);
        for (Int j=0; j < n; j++) {
            dp[i][j] = Array!Int64(k_val+1);
            for (Int t=0; t <= k_val; t++) {
                dp[i][j][t] = INF;
            }
        }
    }

    MinHeap pq;
    dp[0][0][0] = 0;
    insert(pq, (0, 0, 0, 0));

    // Structures for minCostForValue_level and suffix_min_level for each teleport level t
    Int max_val = 10000;
    Array<Array<Int64>> minCostForValue_level = Array!Array!Int64(k_val+1);
    Array<Array<Int64>> suffix_min_level = Array!Array!Int64(k_val+1);
    for (Int t=0; t <= k_val; t++) {
        minCostForValue_level[t] = Array!Int64(max_val+1);
        for (Int v=0; v <= max_val; v++) {
            minCostForValue_level[t][v] = INF;
        }
        suffix_min_level[t] = Array!Int64(max_val+1);
        for (Int v=0; v <= max_val; v++) {
            suffix_min_level[t][v] = INF;
        }
    }

    while (pq.size() > 0) {
        State cur = front(pq);
        removeFront(pq);

        Int64 cost = cur[0];
        Int i = cur[1], j = cur[2], t = cur[3];

        // Skip if not the best for this state
        if (cost > dp[i][j][t]) continue;

        // If reached destination
        if (i == m-1 && j == n-1) {
            return cost;
        }

        Int64 v_val = grid[i][j];
        bool updated = false;
        if (cost < minCostForValue_level[t][v_val]) {
            minCostForValue_level[t][v_val] = cost;
            // Update suffix_min_level for this teleport level t
            Int64 min_temp = INF;
            for (Int v = max_val; v >= 0; v--) {
                if (minCostForValue_level[t][v] < min_temp) {
                    min_temp = minCostForValue_level[t][v];
                }
                suffix_min_level[t][v] = min_temp;
            }
            updated = true;
        }

        // Teleport moves if available and updated
        if (t < k_val && updated) {
            for (Int x=0; x < m; x++) {
                for (Int y=0; y < n; y++) {
                    Int64 val_xy = grid[x][y];
                    Int64 candidate = suffix_min_level[t][val_xy];
                    if (candidate < dp[x][y][t+1]) {
                        dp[x][y][t+1] = candidate;
                        insert(pq, (candidate, x, y, t+1));
                    }
                }
            }
        }

        // Normal moves: right and down
        Int[2] dx = [0, 1];
        Int[2] dy = [1, 0];
        for (Int d=0; d<2; d++) {
            Int ni = i + dx[d];
            Int nj = j + dy[d];
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                Int64 new_cost = cost + grid[ni][nj];
                if (new_cost < dp[ni][nj][t]) {
                    dp[ni][nj][t] = new_cost;
                    insert(pq, (new_cost, ni, nj, t));
                }
            }
        }
    }

    Int64 ans = INF;
    for (Int t=0; t <= k_val; t++) {
        ans = min(ans, dp[m-1][n-1][t]);
    }
    return ans;
}
