use std::collections::BinaryHeap;
use std::cmp::Reverse;

func solve(grid: Array<Array<Int64>>, k: Int64) -> Int64 {
    let INF: Int64 = 1_000_000_000;
    let m = grid.len();
    if m == 0 {
        return 0;
    }
    let n = grid[0].len();
    let k0 = k as usize;

    let mut max_val = 0 as Int64;
    for i in 0..m {
        for j in 0..n {
            if grid[i][j] > max_val {
                max_val = grid[i][j];
            }
        }
    }
    let max_val = max_val as usize;

    let mut dp = [];
    for _ in 0..=k0 {
        let mut layer = [];
        for i in 0..m {
            let mut row = [];
            for j in 0..n {
                row.push(INF);
            }
            layer.push(row);
        }
        dp.push(layer);
    }

    dp[0][0][0] = 0;

    for t in 0..=k0 {
        let mut heap = BinaryHeap::new();
        for i in 0..m {
            for j in 0..n {
                if dp[t][i][j] < INF {
                    heap.push(Reverse((dp[t][i][j], i, j)));
                }
            }
        }

        while let Some(Reverse((cost, i, j))) = heap.pop() {
            if cost != dp[t][i][j] {
                continue;
            }
            if i + 1 < m {
                let ni = i + 1;
                let nj = j;
                let next_cost = cost + grid[ni][nj];
                if next_cost < dp[t][ni][nj] {
                    dp[t][ni][nj] = next_cost;
                    heap.push(Reverse((next_cost, ni, nj)));
                }
            }
            if j + 1 < n {
                let ni = i;
                let nj = j + 1;
                let next_cost = cost + grid[ni][nj];
                if next_cost < dp[t][ni][nj] {
                    dp[t][ni][nj] = next_cost;
                    heap.push(Reverse((next_cost, ni, nj)));
                }
            }
        }

        if t == k0 {
            break;
        }

        let mut min_val = [INF].repeat(max_val + 1);
        for i in 0..m {
            for j in 0..n {
                if dp[t][i][j] < INF {
                    let v = grid[i][j] as usize;
                    if v <= max_val {
                        if dp[t][i][j] < min_val[v] {
                            min_val[v] = dp[t][i][j];
                        }
                    }
                }
            }
        }

        let mut min_suffix = min_val.clone();
        if max_val >= 1 {
            for v in (0..max_val).rev() {
                if min_suffix[v] > min_suffix[v + 1] {
                    min_suffix[v] = min_suffix[v + 1];
                }
            }
        }

        for i in 0..m {
            for j in 0..n {
                let v0 = grid[i][j] as usize;
                let candidate = if v0 <= max_val {
                    min_suffix[v0]
                } else {
                    min_suffix[min_val.len() - 1]
                };
                if candidate < dp[t + 1][i][j] {
                    dp[t + 1][i][j] = candidate;
                }
            }
        }
    }

    let mut ans = INF;
    for t in 0..=k0 {
        if dp[t][m - 1][n - 1] < ans {
            ans = dp[t][m - 1][n - 1];
        }
    }
    ans
}
